const body = $json.body ?? $json;
const name = (body.name || '').toString().trim();
const pdfBase64 = (body.pdf_base64 || '').toString().trim();
const pdfName = (body.pdf_name || 'cv.pdf').toString().trim();
const sampleCvHtml = (body.sample_cv_html || '').toString().trim();

if (!name) throw new Error('name is required in request body');
if (!pdfBase64) throw new Error('pdf_base64 is required in request body');
if (pdfBase64.length < 100) throw new Error('pdf_base64 is too short to be a valid PDF');

return [{ json: { name, pdf_base64: pdfBase64, pdf_name: pdfName, sample_cv_html: sampleCvHtml } }];

const name = $json.name;
const pdfBase64 = $json.pdf_base64;
const pdfName = $json.pdf_name;
const sampleCvHtml = $json.sample_cv_html || '';

const systemPrompt = `You are an expert CV writer and HTML developer. Your job is to convert the content of a candidate's PDF CV into a single, complete, professional HTML document.

STRICT OUTPUT RULES:
- Your ENTIRE response must be the HTML document and nothing else.
- Start your response with <!DOCTYPE html> — no text, no preamble, nothing before it.
- End your response with </html> — no text, no analysis, no change log, nothing after it.
- No markdown, no code fences, no explanations, no commentary anywhere in the response.
- Include <html>, <head>, <style>, and <body> tags.
- Use internal CSS only (inside <style>). No external libraries, no CDN links, no @import.
- Use semantic HTML: <section>, <article>, <header>, <h1>, <h2>, <h3>, <ul>, <li>.
- Do NOT invent, fabricate, or alter any factual content from the CV (names, companies, dates, skills, certifications).
- Do NOT copy any text content from the sample template — use only its structure and style.`;

let userPrompt;

if (sampleCvHtml) {
  userPrompt = `The candidate's CV is the PDF document attached above.\n\nA SAMPLE CV HTML TEMPLATE is provided below. Use it exclusively as your style and layout reference:\n- Replicate its exact CSS, class names, color scheme, fonts, spacing, section order, and HTML structure\n- Replace every piece of sample content with the candidate's actual information from the PDF\n- If the PDF contains a section not present in the sample (e.g. Projects, Languages), add it styled consistently with the existing sections\n- If the sample contains a section with no matching content in the PDF, omit it\n- The output must look like a natural instance of the sample template, not a modified version\n\nSAMPLE CV TEMPLATE (style reference — do NOT copy its content):\n\n${sampleCvHtml}\n\nOutput the complete HTML CV for the candidate above, styled identically to the sample.`;
} else {
  userPrompt = `The PDF CV is attached as the document above. Convert ALL of its content into a professional HTML CV.\n\nDESIGN REQUIREMENTS (apply these since no sample template was provided):\n- Modern, clean, professional — A4 print-friendly, max-width 860px\n- Color scheme: headings #1e293b, accent #2563eb, muted #64748b, header band #f8fafc\n- Section headings: 11px uppercase, letter-spacing 0.08em, accent color with 2px bottom border\n- Name: 28px bold; job title: 15px muted; contact row: 13px items separated by " · "\n- Body: system-ui sans-serif, 13.5px, line-height 1.55\n- Company names: 14px bold; dates: 12px right-aligned muted\n- Bullet points: margin-left 18px, line-height 1.5; 20px spacing between sections\n- ATS-friendly: no layout tables, no multi-column main body\n- Print @media: 12px font, black links, page-break-inside avoid on sections\n\nOutput only the complete HTML file.`;
}

return [{
  json: {
    name,
    pdf_base64: pdfBase64,
    pdf_name: pdfName,
    has_sample: !!sampleCvHtml,
    anthropic_model: 'claude-sonnet-4-6',
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

const meta = $('Validate Inputs').item.json;
const content = $json.content || [];

if (!Array.isArray(content) || content.length === 0) {
  const stopReason = $json.stop_reason || 'unknown';
  throw new Error(`Claude returned no content blocks (stop_reason: ${stopReason}). Check API credits or model availability.`);
}

const rawText = content
  .filter(part => part.type === 'text')
  .map(part => part.text)
  .join('\n')
  .trim();

if (!rawText) throw new Error('Claude returned an empty text response');

// Strip markdown code fences
let html = rawText
  .replace(/^```html\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

// Extract only the HTML document — discard any preamble or postamble Claude added
const htmlStart = html.search(/<!doctype\s+html|<html[\s>]/i);
const htmlEnd = html.lastIndexOf('</html>');
if (htmlStart !== -1 && htmlEnd !== -1 && htmlEnd > htmlStart) {
  html = html.slice(htmlStart, htmlEnd + 7).trim();
}

if (!html.toLowerCase().includes('<html') && !html.toLowerCase().includes('<!doctype')) {
  throw new Error('Could not extract a valid HTML document from Claude response. Check the prompt or try again.');
}

return [{
  json: {
    success: true,
    name: meta.name,
    pdf_name: meta.pdf_name,
    html
  }
}];

const errBody = $json;
let message = 'Claude API error';

if (errBody && typeof errBody === 'object') {
  const e = errBody.error;
  if (e && typeof e === 'object' && typeof e.message === 'string') {
    message = `Claude API error: ${e.message}`;
  } else if (typeof errBody.message === 'string') {
    message = errBody.message;
  } else if (typeof errBody.statusCode === 'number') {
    message = `Claude API returned HTTP ${errBody.statusCode}`;
  }
}

return [{ json: { success: false, error: message } }];
